function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by time in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find data structure to keep track of connected components
    class UnionFind {
        parent: number[];
        rank: number[];
        count: number;

        constructor(size: number) {
            this.parent = Array(size).fill(0);
            this.rank = Array(size).fill(0);
            this.count = size;
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false; // Already connected
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }

            this.count--;
            return true;
        }
    }

    const uf = new UnionFind(n);

    let result: number = 0;

    // Iterate through edges in order of increasing time
    for (const [u, v, time] of edges) {
        // If the nodes are not connected, union them
        if (uf.union(u, v)) {
            // Check if the number of connected components is >= k
            if (uf.count >= k) {
                result = time;
                break;
            }
        }
    }

    return result;
}

